const resultados = $input.all();
const extraerDatos = $('Extraer Datos').first().json;

// Si el primer resultado tiene row_number, significa que encontró un registro existente
const primerItem = resultados[0].json;
const duplicado = primerItem.hasOwnProperty('row_number');

return [{ json: { ...extraerDatos, duplicado: duplicado } }];

// CORRECCIÓN BUG #5: Parsear el JSON de la IA UNA sola vez aquí
// y exponer los campos como propiedades planas para que Organizar Datos los use.
const raw = $input.first().json.text.trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  // Si falla el parse, intentar extraer el JSON del texto (por si el modelo añade texto extra)
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('No se pudo parsear la respuesta de la IA: ' + raw);
  }
}

const extraerDatos = $('Extraer Datos').first().json;

return [{
  json: {
    nombre: parsed.nombre || '',
    email: parsed.email || '',
    nivel: parsed.nivel || '',
    puntuacion: Number(parsed.puntuacion) || 0,
    resumen: parsed.resumen || '',
    fecha: $now.setZone('America/Bogota').toFormat('d/M/yyyy'),
    vacante: extraerDatos.vacante,
    "estado del proceso": "Aplicó"
  }
}];

